export type GlossaryCategory =
  | "basics"
  | "bidding"
  | "tracking"
  | "optimization"
  | "advanced";

export type GlossaryTerm = {
  /** URL-safe slug, used for #anchor and internal linking */
  slug: string;
  /** Primary term display name (EN-first for acronyms) */
  term: string;
  /** Serbian variant of term, if different */
  termSr?: string;
  /** Alternative spellings, aliases (for search + schema alternateName) */
  aliases?: string[];
  category: GlossaryCategory;
  /** 1-sentence definition — featured-snippet target */
  shortDefinitionSr: string;
  shortDefinitionEn: string;
  /** 2-4 sentence full definition */
  definitionSr: string;
  definitionEn: string;
  /** Optional formula (identical for both locales) */
  formula?: string;
  /** Numerical example with context */
  exampleSr?: string;
  exampleEn?: string;
  /** Optional benchmarks table for SR market */
  benchmarks?: Array<{ label: string; range: string }>;
  /** Related term slugs — renders as inline cross-links */
  relatedTerms?: string[];
  /** Optional blog slug to link for deeper read */
  relatedPostSr?: string;
  relatedPostEn?: string;
};

