/** Quick lookup by slug */
export function getGlossaryTerm(slug: string): GlossaryTerm | undefined {
  return glossaryTerms.find((t) => t.slug === slug);
}

/** Get all terms in a category */
export function getGlossaryByCategory(
  category: GlossaryCategory
): GlossaryTerm[] {
  return glossaryTerms.filter((t) => t.category === category);
}

/** Count by category */
export function getCategoryCounts(): Record<GlossaryCategory, number> {
  return {
    basics: getGlossaryByCategory("basics").length,
    bidding: getGlossaryByCategory("bidding").length,
    tracking: getGlossaryByCategory("tracking").length,
    optimization: getGlossaryByCategory("optimization").length,
    advanced: getGlossaryByCategory("advanced").length,
  };
}
